<tr>
<td rowspan="2">

```js
function setup() {
  createCanvas(400, 400, WEBGL);
  pixelDensity(2);
  setAttributes({
    alpha: true,
    premultipliedAlpha: true
  });
  noFill();
  stroke(200, 200, 255);
  strokeWeight(1);
}
function draw() {
  // black w/ alpha zero
  background(0, 0, 0, 0);
  scale(4);
  box();
  noLoop();
}
```
